	<li><span style=\"font-size:12pt\"><span style=\"font-family:Aptos,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Output Lines &ndash; H-V</span></span></span></span></li>
	<li><span style=\"font-size:12pt\"><span style=\"font-family:Aptos,sans-serif\"><span style=\"font-size:13.0pt\"><span style=\"font-family:&quot;Calibri&quot;,sans-serif\">Auto-Levelling Range - &plusmn;5&deg;</span></span></span></span></li>
